import React from 'react';

const Dashboard = () => {
  return (
    <div>
      <h2>Dashboard de Indicadores</h2>
      <p>Em breve, aqui você verá seus gastos por categoria e gráficos de evolução.</p>
      <div style={{ width: '100%', height: '300px', background: '#f9f9f9', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px dashed #ccc' }}>
        Área do Gráfico
      </div>
    </div>
  );
};

export default Dashboard;
